// HumanBrowser — main class wrapping Playwright with full human behavior simulation

import { chromium } from 'playwright-core';
import { moveTo, clickElement, clickAt } from './src/mouse.js';
import { type } from './src/keyboard.js';
import { scroll, preExitScroll, scrollToElement } from './src/scroll.js';
import { navigateTo, TabManager } from './src/navigation.js';
import { sleep } from './src/utils.js';

const CHROMIUM_PATH = '/usr/bin/chromium';

export class HumanBrowser {
  constructor() {
    this.browser = null;
    this.context = null;
    this.tabs = null;
    this.mouseState = { x: null, y: null };
  }

  // Connect to an already-running browser via Chrome DevTools Protocol.
  // Used for MultiLogin X profiles — MultiLogin X starts Mimic (Chromium), we connect to it.
  // Do NOT call close() on a CDP-connected browser — it will kill the MultiLogin X process.
  async connectCDP(wsUrl) {
    this.browser = await chromium.connectOverCDP(wsUrl);
    const contexts = this.browser.contexts();
    this.context = contexts[0] || await this.browser.newContext();
    this.tabs = new TabManager(this.context);
    return this;
  }

  async launch() {
    this.browser = await chromium.launch({
      executablePath: CHROMIUM_PATH,
      headless: true,
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-dev-shm-usage',
        '--disable-blink-features=AutomationControlled',
        '--disable-infobars',
        '--window-size=1366,768',
      ],
    });

    this.context = await this.browser.newContext({
      viewport: { width: 1366, height: 768 },
      userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
      locale: 'en-US',
      timezoneId: 'Asia/Kuala_Lumpur',
    });

